tim80 = ""
tim70 = "IKIAPSMLAADFANLENDVQMVNQSQADWFHMDIMDGVFVPNISFGMPVLKAMAQHAKKPLDVHLMIVDPDRYIQTFANLGAAVLTVHAEACTHIHRTVQAIKAAGMKAGVALNPHTPITVLEEIISDLDLICIMSVNPGFGGQQFIENTYDKVRRLRALINAKNAEVMIEIDGGVTSDNAAALVQAGADVLVAGSFVFKSQKPSETISN"

alignments = pairwise2.align.globalxx(seq1, tim80)
